import java.io.File;
import java.util.Scanner;

public class SafePathTraversal {

    private static final String BASE_DIRECTORY = "/path/to/directory/";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter file name:");
        String fileName = scanner.nextLine();

        if (isPathSafe(fileName)) {
            File file = new File(BASE_DIRECTORY + fileName);

            if (file.exists()) {
                System.out.println("File exists!");
                // Do something with the file
            } else {
                System.out.println("File not found.");
            }
        } else {
            System.out.println("Invalid file name.");
        }
    }

    private static boolean isPathSafe(String fileName) {
        // Perform validation to ensure the fileName does not contain any directory traversal characters
        return !fileName.contains("..") && !fileName.contains("/") && !fileName.contains("\\");
    }
}

